#!/usr/bin/env python3
"""
A creative ASCII art generator that transforms text into art using random fonts and colors.
Requires: pyfiglet (pip install pyfiglet) and termcolor (pip install termcolor)
"""

import sys
import random
import argparse

try:
    import pyfiglet
except ImportError:
    sys.exit("Error: pyfiglet module not found. Please install it via 'pip install pyfiglet'.")

try:
    from termcolor import colored
except ImportError:
    # Fallback: if termcolor isn't available, define a dummy colored() function.
    def colored(text, color):
        return text

def get_random_font():
    """Return a randomly selected font from pyfiglet's available fonts."""
    fonts = pyfiglet.FigletFont.getFonts()
    return random.choice(fonts)

def get_random_color():
    """Return a random terminal color for art styling."""
    colors = ['red', 'green', 'yellow', 'blue', 'magenta', 'cyan', 'white']
    return random.choice(colors)

def generate_ascii_art(text, font, color):
    """Generate ASCII art from text with specified font and color."""
    fig = pyfiglet.Figlet(font=font)
    art = fig.renderText(text)
    return colored(art, color)

def main():
    parser = argparse.ArgumentParser(
        description="Generate creative ASCII art from input text using a random font and color."
    )
    parser.add_argument("text", nargs="*", help="Text to convert to ASCII art (wrap in quotes if multiple words).")
    args = parser.parse_args()

    if args.text:
        input_text = " ".join(args.text)
    else:
        input_text = input("Enter text to convert to ASCII art: ")

    # Pick a random font and a random color
    chosen_font = get_random_font()
    chosen_color = get_random_color()

    art = generate_ascii_art(input_text, chosen_font, chosen_color)

    # Decorate the output with a header/footer banner for extra flair.
    divider = "=" * 80
    print(divider)
    print(f"Using font: {chosen_font} | Color: {chosen_color}")
    print(divider)
    print(art)
    print(divider)

if __name__ == "__main__":
    main()

