def choose_random_font():
    fonts = pyfiglet.FigletFont.getFonts()
    return random.choice(fonts)

def create_ascii_art(text, font):
    figlet = pyfiglet.Figlet(font=font)
    return figlet.renderText(text)

def add_border(art, border_char='*'):
    lines = art.splitlines()
    if not lines:
        return art
    max_length = max(len(line) for line in lines)
    border_line = border_char * (max_length + 4)
    bordered_art = [border_line]
    for line in lines:
        bordered_art.append(f"{border_char} {line.ljust(max_length)} {border_char}")
    bordered_art.append(border_line)
    return "\n".join(bordered_art)

def main():
    text = input("Enter text to convert to ASCII art: ")
    if not text.strip():
        print("No text provided. Exiting.")
        sys.exit(0)

    selected_font = choose_random_font()
    art = create_ascii_art(text, selected_font)

    # Create a visually interesting border pattern using two different characters
    border_choice = random.choice([('*', '='), ('#', '-'), ('@', '%')])
    primary_border, secondary_border = border_choice

    # Alternate border style based on line index.
    lines = art.splitlines()
    max_length = max(len(line) for line in lines)
    decorated_lines = []
    for idx, line in enumerate(lines):
        border_char = primary_border if idx % 2 == 0 else secondary_border
        decorated_lines.append(f"{border_char} {line.ljust(max_length)} {border_char}")

    top_border = primary_border * (max_length + 4)
    bottom_border = primary_border * (max_length + 4)

    final_art = "\n".join([top_border] + decorated_lines + [bottom_border])

