            wave_height = int(3 * math.sin(i * 0.5) + 3)
            line = ' ' * wave_height + char
            result.append(line)
        return '\n'.join(result)

    def generate_spiral_text(self, text: str) -> str:
        """Generate spiral ASCII art"""
        if not text:
            return ""

        size = max(10, len(text) + 5)
        grid = [[' ' for _ in range(size)] for _ in range(size)]

        # Spiral coordinates
        x, y = size // 2, size // 2
        dx, dy = 0, -1

        for i, char in enumerate(text):
            if 0 <= x < size and 0 <= y < size:
                grid[y][x] = char

            # Change direction in spiral pattern
            if x == y or (x < 0 and x == -y) or (x > 0 and x == 1 - y):
                dx, dy = -dy, dx

            x, y = x + dx, y + dy

        return '\n'.join(''.join(row) for row in grid)

    def generate_diamond_text(self, text: str) -> str:
        """Generate diamond-shaped ASCII art"""
        lines = []
        mid = len(text) // 2

        # Top half of diamond
        for i in range(mid + 1):
            spaces = ' ' * (mid - i)
            chars = ' '.join(text[max(0, mid - i):mid + i + 1])
            lines.append(spaces + chars)

        # Bottom half of diamond
        for i in range(mid - 1, -1, -1):
            spaces = ' ' * (mid - i)
            chars = ' '.join(text[max(0, mid - i):mid + i + 1])
            lines.append(spaces + chars)

        return '\n'.join(lines)
